def dfs(r, c):
    if not (0<=r<rows and 0<=c<cols) or board[r][c] != 'O': return
    board[r][c] = 'T'  # temporary mark
    dfs(r+1,c); dfs(r-1,c); dfs(r,c+1); dfs(r,c-1)
# Mark border-connected Os
for r in range(rows):
    for c in [0, cols-1]:
        if board[r][c] == 'O': dfs(r,c)
for c in range(cols):
    for r in [0, rows-1]:
        if board[r][c] == 'O': dfs(r,c)
# Flip
for r in range(rows):
    for c in range(cols):
        if board[r][c] == 'O': board[r][c] = 'X'
        elif board[r][c] == 'T': board[r][c] = 'O'
# Time: O(m·n)  Space: O(m·n)
